// Créer le contexte ML
var mlContext = new MLContext(seed: 42);

// Note: la classe d'entrée reflète le nom de colonne ONNX du modèle
// iris_model.onnx produit par scripts/ml/generate_iris_onnx.py : le modèle
// attend une entrée nommée 'input'. On utilise donc [ColumnName("input")] pour
// mapper la propriété C# 'Features' vers la colonne attendue par le modèle.
public class OnnxInputData
{
    [VectorType(4)]
    [ColumnName("input")]
    public float[] Features { get; set; }
}

// Note: la classe de sortie reflète la signature ONNX du modèle iris_model.onnx
// produit par scripts/ml/generate_iris_onnx.py (skl2onnx avec zipmap=False) :
//   - output "label" : int64 (classe prédite, 0/1/2) — exposé sous forme Vector<Int64, 1>
//   - output "probabilities" : float[3] (probabilités par classe)
// OnnxOutputData utilise donc des noms de colonnes alignés sur les noms ONNX,
// avec des types tableau pour rester compatible avec ML.NET TypedCursorable.
public class OnnxOutputData
{
    [ColumnName("label")]
    public long[] PredictedLabel { get; set; }
    [VectorType(3)]
    [ColumnName("probabilities")]
    public float[] Probabilities { get; set; }
}

