// Creer le contexte ML
var mlContext = new MLContext(seed: 42);

// Charger les donnees
var trainingData = mlContext.Data.LoadFromEnumerable(movieData);

Console.WriteLine("=== Configuration du systeme de recommandation ===");
Console.WriteLine("Algorithme : Matrix Factorization (Collaborative Filtering)");

// Pipeline : convertir UserId et MovieId en types Key, puis appliquer MatrixFactorization
var pipeline = mlContext.Transforms.Conversion.MapValueToKey("UserIdKey", "UserId")
    .Append(mlContext.Transforms.Conversion.MapValueToKey("MovieIdKey", "MovieId"))
    .Append(mlContext.Recommendation().Trainers.MatrixFactorization(
        new MatrixFactorizationTrainer.Options
        {
            MatrixColumnIndexColumnName = "UserIdKey",
            MatrixRowIndexColumnName = "MovieIdKey",
            LabelColumnName = "Rating",
            NumberOfIterations = 20,
            ApproximationRank = 10  // Nombre de facteurs latents
        }));

Console.WriteLine("Nombre d'iterations : 20");
Console.WriteLine("Facteurs latents (ApproximationRank) : 10");

